import anthropic
import json
import time
import logging
from typing import Any

# Domain 1: Software Engineering -- structured logging, error handling
logging.basicConfig(
    level=logging.INFO,
    format="%(asctime)s %(levelname)s %(name)s %(message)s",
)
log = logging.getLogger("agent")

client = anthropic.Anthropic()

# Domain 2: LLM Fundamentals -- tool definitions using function calling
tools = [
    {
        "name": "calculator",
        "description": "Evaluates a mathematical expression and returns the result.",
        "input_schema": {
            "type": "object",
            "properties": {
                "expression": {
                    "type": "string",
                    "description": "A Python-evaluable arithmetic expression, e.g. '2 ** 10 + 3'",
                }
            },
            "required": ["expression"],
        },
    },
    {
        "name": "lookup_fact",
        "description": "Returns a known fact from an in-memory store.",
        "input_schema": {
            "type": "object",
            "properties": {
                "query": {"type": "string", "description": "The fact to look up"}
            },
            "required": ["query"],
        },
    },
]

# Domain 3: Agent Systems Design -- tool execution and loop
FACT_STORE = {
    "speed of light": "299,792,458 metres per second",
    "planck constant": "6.626 x 10^-34 joule-seconds",
}


def execute_tool(name: str, inputs: dict[str, Any]) -> str:
    """Execute a tool call and return its string output."""
    if name == "calculator":
        try:
            # Domain 5: Security -- restrict eval to numeric expressions only
            expr = inputs["expression"]
            allowed = set("0123456789+-*/()., **%")
            if not all(c in allowed or c.isspace() for c in expr):
                return "Error: expression contains disallowed characters"
            result = eval(expr, {"__builtins__": {}})
            return str(result)
        except Exception as e:
            return f"Error: {e}"
    elif name == "lookup_fact":
        query = inputs["query"].lower()
        for key, value in FACT_STORE.items():
            if key in query:
                return value
        return "Fact not found in store."
    return f"Unknown tool: {name}"


def run_agent(user_message: str, max_iterations: int = 5) -> str:
    """Agent loop: call LLM, execute tool calls, continue until final answer."""
    messages = [{"role": "user", "content": user_message}]
    iterations = 0

    while iterations < max_iterations:
        iterations += 1
        start = time.monotonic()

        response = client.messages.create(
            model="claude-opus-4-5",
            max_tokens=1024,
            tools=tools,
            messages=messages,
        )

        # Domain 4: Observability -- log latency and token usage
        latency_ms = (time.monotonic() - start) * 1000
        log.info(
            "llm_call iteration=%d stop_reason=%s latency_ms=%.0f "
            "input_tokens=%d output_tokens=%d",
            iterations,
            response.stop_reason,
            latency_ms,
            response.usage.input_tokens,
            response.usage.output_tokens,
        )

        if response.stop_reason == "end_turn":
            for block in response.content:
                if hasattr(block, "text"):
                    return block.text
            return ""

        if response.stop_reason == "tool_use":
            messages.append({"role": "assistant", "content": response.content})
            tool_results = []
            for block in response.content:
                if block.type == "tool_use":
                    log.info("tool_call name=%s inputs=%s", block.name, json.dumps(block.input))
                    result = execute_tool(block.name, block.input)
                    log.info("tool_result name=%s result=%s", block.name, result)
                    tool_results.append({
                        "type": "tool_result",
                        "tool_use_id": block.id,
                        "content": result,
                    })
            messages.append({"role": "user", "content": tool_results})
            continue

        break

    return "Max iterations reached without final answer."


# Domain 4: Evaluation -- simple correctness check
def evaluate_agent(test_cases: list[dict]) -> dict:
    """Run the agent on test cases and return accuracy metrics."""
    results = {"passed": 0, "failed": 0, "errors": []}
    for tc in test_cases:
        try:
            answer = run_agent(tc["question"])
            passed = tc["expected"].lower() in answer.lower()
            if passed:
                results["passed"] += 1
            else:
                results["failed"] += 1
                results["errors"].append({
                    "question": tc["question"],
                    "expected": tc["expected"],
                    "got": answer[:100],
                })
        except Exception as e:
            results["failed"] += 1
            results["errors"].append({"question": tc["question"], "error": str(e)})
    results["accuracy"] = results["passed"] / max(len(test_cases), 1)
    return results


